import{_ as s,o as n,c as p,ag as e}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"常见错误以及解决办法","description":"","frontmatter":{},"headers":[],"relativePath":"docs/error.md","filePath":"docs/error.md","lastUpdated":null}'),o={name:"docs/error.md"};function t(i,a,l,c,r,d){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="常见错误以及解决办法" tabindex="-1">常见错误以及解决办法 <a class="header-anchor" href="#常见错误以及解决办法" aria-label="Permalink to &quot;常见错误以及解决办法&quot;">​</a></h1><h2 id="为什么询问ai大模型的名称-它们无法正确回答" tabindex="-1">为什么询问ai大模型的名称，它们无法正确回答？ <a class="header-anchor" href="#为什么询问ai大模型的名称-它们无法正确回答" aria-label="Permalink to &quot;为什么询问ai大模型的名称，它们无法正确回答？&quot;">​</a></h2><p><strong>训练数据的时间差</strong></p><p>模型训练时使用的数据通常早于模型发布，训练数据中不包含关于&quot;自己&quot;的信息，模型无法&quot;知道&quot;自己最终会被命名为什么</p><p><strong>自我认知的缺失</strong></p><p>AI模型本质上是在预测下一个词，它们没有真正的&quot;自我意识&quot;，关于自身身份的信息需要被明确编程或注入</p><p>如果你需要模型正确回答自己是哪个模型，可以在系统提示词中加入相关信息，例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You are GPT-4, a large language model trained by OpenAI.</span></span></code></pre></div><h2 id="为什么-chatgpt-claude-等官方网页版应用能够正确回答自己是哪个模型" tabindex="-1">为什么 ChatGPT / Claude 等官方网页版应用能够正确回答自己是哪个模型？ <a class="header-anchor" href="#为什么-chatgpt-claude-等官方网页版应用能够正确回答自己是哪个模型" aria-label="Permalink to &quot;为什么 ChatGPT / Claude 等官方网页版应用能够正确回答自己是哪个模型？&quot;">​</a></h2><p>这是因为官方网页版应用是to C 产品，它们在系统提示词中已经加入了相关信息，所以它们能够正确回答自己是哪个模型。</p><h2 id="常见错误代码" tabindex="-1">常见错误代码 <a class="header-anchor" href="#常见错误代码" aria-label="Permalink to &quot;常见错误代码&quot;">​</a></h2><p>错误代码</p><p>说明</p><p>400 Bad Request</p><p>请求格式错误或无效。这通常意味着你的请求参数有误，需要你检查并修正请求参数。</p><p>401 Unauthorized</p><p>请求令牌无效。这通常意味着你的请求令牌有误，需要你检查并修正请求参数。</p><p>403 Forbidden</p><p>余额不足</p><p>404 Not Found</p><p>请求地址错误</p><p>413 Request Entity Too Large</p><p>请求体太大。你可能需要减少你的请求数据量。</p><p>429 Too Many Requests</p><p>由于短时间内发送过多的请求，你已经超过了你的速率限制。</p><p>500 Internal Server Error</p><p>服务器内部错误。</p><p>503 Service Unavailable</p><p>服务暂时不可用。这可能是由于 OpenAI 正在进行维护或者服务器过载。</p><h2 id="后台额度充足-使用-api-提示额度不足" tabindex="-1">后台额度充足，使用 API 提示额度不足？ <a class="header-anchor" href="#后台额度充足-使用-api-提示额度不足" aria-label="Permalink to &quot;后台额度充足，使用 API 提示额度不足？&quot;">​</a></h2><p>请确认你后台创建的令牌余额充足</p><h2 id="提示当前分组下没有可用渠道" tabindex="-1">提示当前分组下没有可用渠道？ <a class="header-anchor" href="#提示当前分组下没有可用渠道" aria-label="Permalink to &quot;提示当前分组下没有可用渠道？&quot;">​</a></h2><ol><li>确认模型名称是否正确</li><li>确认当前渠道类型是否有该模型</li></ol><h2 id="为什么gpt-5-等推理模型会返回空响应内容" tabindex="-1">为什么GPT-5 等推理模型会返回空响应内容？ <a class="header-anchor" href="#为什么gpt-5-等推理模型会返回空响应内容" aria-label="Permalink to &quot;为什么GPT-5 等推理模型会返回空响应内容？&quot;">​</a></h2><p>请检查是否设置了<code>max_tokens</code> 参数，如果设置了，请尝试移除该参数，或者将其设置为一个较大的值。</p><p>这是因为<code>推理tokens</code> 同样会计算在<code>max_tokens</code>中，如果设置的值过小，当推理tokens &gt; <code>max_tokens</code> 时，已经满足了限制条件，会立即停止输出内容，导致返回空响应。</p><p>特别是OpenAI的推理模型，由于OpenAI不会返回推理内容，所以会直接返回空响应内容。</p><p>chat接口可以通过返回的<code>finish_reason</code> 字段来判断是否是因为<code>max_tokens</code> 导致的响应中断。</p><p>finish_reason 内容</p><p>说明</p><p>stop</p><p>正常结束</p><p>length</p><p>达到 max_tokens 限制</p><p>content_filter</p><p>内容被过滤</p><p>response接口通过判断<code>status</code>字段，如果<code>status</code> 字段为<code>completed</code> 则表示正常结束，如果为<code>incomplete</code> 则表示出现异常，然后通过<code>incomplete_details.reason</code> 字段来判断具体原因。</p><p>reason 内容</p><p>说明</p><p>max_output_tokens</p><p>达到 max_tokens 限制</p><h2 id="为什么o3-deep-research-o4-mini-deep-research-请求报错" tabindex="-1">为什么<code>o3-deep-research</code> / <code>o4-mini-deep-research</code> 请求报错 <a class="header-anchor" href="#为什么o3-deep-research-o4-mini-deep-research-请求报错" aria-label="Permalink to &quot;为什么\`o3-deep-research\` / \`o4-mini-deep-research\` 请求报错&quot;">​</a></h2><p>OpenAI的<code>deep-research</code>模型必须要使用<code>网络搜索工具</code>或者<code>mcp工具</code>才能运行。</p><h3 id="使用web-search-preview工具" tabindex="-1">使用<code>web_search_preview</code>工具 <a class="header-anchor" href="#使用web-search-preview工具" aria-label="Permalink to &quot;使用\`web_search_preview\`工具&quot;">​</a></h3><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --location --request POST &#39;https://api.maisi-ai.com/v1/responses&#39; \\</span></span>
<span class="line"><span>--header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>--header &#39;Authorization: Bearer sk-xxxx&#39; \\</span></span>
<span class="line"><span>--data-raw &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;o3-deep-research&quot;,</span></span>
<span class="line"><span>    &quot;stream&quot; : true,</span></span>
<span class="line"><span>    &quot;input&quot;: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        &quot;role&quot;: &quot;user&quot;,</span></span>
<span class="line"><span>        &quot;content&quot;: &quot;今天是2025-07-23,有哪些新闻？&quot;</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;tools&quot;: [</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>            &quot;type&quot;: &quot;web_search_preview&quot;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>}&#39;</span></span></code></pre></div><h3 id="使用mcp工具" tabindex="-1">使用<code>mcp</code>工具 <a class="header-anchor" href="#使用mcp工具" aria-label="Permalink to &quot;使用\`mcp\`工具&quot;">​</a></h3><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;o3-deep-research&quot;,</span></span>
<span class="line"><span>    &quot;stream&quot; : true,</span></span>
<span class="line"><span>    &quot;input&quot;: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        &quot;role&quot;: &quot;user&quot;,</span></span>
<span class="line"><span>        &quot;content&quot;: &quot;获取网页内容并总结：https://xxxxx&quot;</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;tools&quot;: [</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>            &quot;type&quot;: &quot;mcp&quot;,</span></span>
<span class="line"><span>            &quot;server_label&quot;: &quot;modelscope&quot;,</span></span>
<span class="line"><span>            &quot;server_url&quot;: &quot;https://mcp.api-inference.modelscope.net/xxxx/sse&quot;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="gpt-5-gpt-5-mini-为什么这么慢" tabindex="-1">GPT-5 / GPT-5-mini 为什么这么慢？ <a class="header-anchor" href="#gpt-5-gpt-5-mini-为什么这么慢" aria-label="Permalink to &quot;GPT-5 / GPT-5-mini 为什么这么慢？&quot;">​</a></h2><p>这是因为GPT-5系列是推理模型，而OpenAI不输出推理内容，所以我们需要等待OpenAI推理完成后，才能返回结果。</p><p>如果想要响应速度更快，可以降低推理程度。例如：</p><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;model&quot;: &quot;gpt-5&quot;,</span></span>
<span class="line"><span>  &quot;stream&quot;: true,</span></span>
<span class="line"><span>  &quot;input&quot;: &quot;hi~&quot;,</span></span>
<span class="line"><span>  &quot;reasoning&quot;: {</span></span>
<span class="line"><span>    &quot;effort&quot;: &quot;minimal&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>努力程度</p><p>说明</p><p>minimal</p><p>最小努力，响应速度最快, 仅支持gpt-5系列模型使用， o系列无法使用</p><p>low</p><p>较低努力，响应速度较快</p><p>medium</p><p>中等努力，响应速度较慢</p><p>high</p><p>最大努力，响应速度最慢</p><h2 id="gemini-2-5-flash为什么这么慢" tabindex="-1">Gemini 2.5 Flash为什么这么慢 <a class="header-anchor" href="#gemini-2-5-flash为什么这么慢" aria-label="Permalink to &quot;Gemini 2.5 Flash为什么这么慢&quot;">​</a></h2><p>这是因为<code>Gemini 2.5 Flash</code> 是混合模型，默认开启推理。</p><p>如果想要响应速度更快，可以关闭推理。</p><p>OpenAI chat API 接口可以直接请求<code>gemini-2.5-flash-nothinking</code>。</p><p>如果使用Gemini API 接口，需要设置<code>thinkingConfig</code> 参数：</p><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --location --request POST &#39;https://api.maisi-ai.com/gemini/v1beta/models/gemini-2.5-flash:streamGenerateContent?alt=sse&#39; \\</span></span>
<span class="line"><span>--header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>--header &#39;x-goog-api-key: sk-xxxxx&#39; \\</span></span>
<span class="line"><span>--data-raw &#39;{</span></span>
<span class="line"><span>  &quot;contents&quot;: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;role&quot;: &quot;user&quot;,</span></span>
<span class="line"><span>      &quot;parts&quot;: [</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>          &quot;text&quot;: &quot;hi~&quot;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>      ]</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;generationConfig&quot;: {</span></span>
<span class="line"><span>    &quot;thinkingConfig&quot;: {</span></span>
<span class="line"><span>      &quot;includeThoughts&quot;: false,</span></span>
<span class="line"><span>      &quot;thinkingBudget&quot;: 0</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}&#39;</span></span></code></pre></div><h2 id="为什么推理模型很容易请求失败-超时" tabindex="-1">为什么推理模型很容易请求失败 / 超时 ？ <a class="header-anchor" href="#为什么推理模型很容易请求失败-超时" aria-label="Permalink to &quot;为什么推理模型很容易请求失败 / 超时 ？&quot;">​</a></h2><p>这是因为推理模型会需要更多的耗时，特别是在遇到复杂的任务时， 耗时可能超过<code>2000s</code>，所以很容易请求失败或者超时。 解决方法：</p><ol><li>尽量使用<code>stream</code> 模式，避免请求超时。</li><li>如果想要在<code>非 stream</code> 模式下使用，需要增加请求超时设置。</li><li>也可以在<code>令牌管理</code>页面中，打开<code>心跳设置(实验性)</code>的开关。</li></ol><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>心跳设置是指当在请求时，如果长时间没有返回数据，您的客户端可能会因为超时机制而断开连接。为了保持TCP连接不会因超时中断，您可以开启心跳设置，当请求超出您设置的开始时间，且无响应时，我们将会每隔5秒发送一次心跳请求(非流式请求返回空行，流式返回::PING)，以保持连接。注意：如果您在使用中转程序时，请不要开启该设置，可能会出现不可预知的问题。</p></div>`,85)])])}const q=s(o,[["render",t]]);export{h as __pageData,q as default};
